"use strict";exports.camelCase=function(e){return e.replace(/(?:^\w|[A-Z]|\b\w)/g,(e,r)=>0===r?e.toLowerCase():e.toUpperCase()).replace(/[\s\-_]+/g,"")},exports.capitalize=function(e){return 0===e.length?e:e.charAt(0).toUpperCase()+e.slice(1)},exports.slugify=function(e){return e.trim().toLowerCase().replace(/[^a-z0-9\s-]/g,"").replace(/[\s-]+/g,"-").replace(/^-+|-+$/g,"")},exports.truncate=function(e,r,t="..."){return e.length<=r?e:e.slice(0,r)+t};
